void PwrRccInit(void){
	PWR->CR  = 0x00000000;
	PWR->CSR = 0x00000000;

	RCC->CR   =   0x00000083;
	RCC->CFGR =   0x00000000;
	RCC->CIR  =   0x00000000;
	}

void GPIOInit(void){
	RCC->APB2ENR   =   0x0000000c ;
	RCC->APB2RSTR |=   0x0000000c ;
	RCC->APB2RSTR &= ~(0x0000000c);
	GPIOA->CRL     =   0x22222222 ;
	GPIOA->CRH     =   0x44444444 ;
	GPIOB->CRL     =   0x44442222 ;
	GPIOB->CRH     =   0x44444444 ;
	}

void timer3Init(void){
	RCC->APB1RSTR |= 0x0002;	//for timer 3
	RCC->APB1RSTR &= ~(0x0002);
	RCC->APB1ENR |=0x0002;//RCC_APB1ENR_TIM3EN
	TIM3->CR2 = 0x000;
	TIM3->SMCR = 0x000;
	TIM3->DIER = 0x001;
	TIM3->PSC = (2-1);//prescaler
	TIM3->ARR = (417-1);//auto-reload
	TIM3->CCR4 = 3906/100;
	TIM3->CCMR2 = 0xFC00;
	TIM3->CCER = 0x0000;
	TIM3->CR1 = 0x000;	//disable
	NVIC_EnableIRQ(TIM3_IRQn);
	}

void TIM3_IRQHandler(void){
	TIM3->SR &= ~0x00000001;
	if((tdCount)<(bits+2)){
		if((tData & (1<<tdCount))==(1<<tdCount))
			GPIOB->ODR |= 0x0004;
		else
			GPIOB->ODR &= ~(0x0004);
		tdCount++;
		}
	else{
		TIM3->CR1 = 0x000;	//disable
		txBusy = 0;
		}
	}

void send7(uint16_t a){
	tData = (a<<1) | (1<<(bits+1));
	tdCount=0;
	txBusy = 1;
	TIM3->CNT = 1;//counter=1
	TIM3->CR1 = 0x001;	//enable
	}

void puts(uint8_t* a){
	while(*a){
		while(txBusy==1);
		send7(*(a++));
		}
	}

